import{_ as a,o as i,c as e,aA as t}from"./chunks/framework.DSLGZMB4.js";const c=JSON.parse('{"title":"Use Koma from the Command Line","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/1-4-use-koma-cli.md","filePath":"how-to/1-4-use-koma-cli.md","lastUpdated":null}'),n={name:"how-to/1-4-use-koma-cli.md"};function p(h,s,l,o,d,k){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="Use-Koma-from-the-Command-Line" tabindex="-1">Use Koma from the Command Line <a class="header-anchor" href="#Use-Koma-from-the-Command-Line" aria-label="Permalink to &quot;Use Koma from the Command Line {#Use-Koma-from-the-Command-Line}&quot;">​</a></h1><p>KomaMRI provides the <code>koma</code> Julia app for opening the UI or running simulations from a terminal.</p><h2 id="Installing-the-App" tabindex="-1">Installing the App <a class="header-anchor" href="#Installing-the-App" aria-label="Permalink to &quot;Installing the App {#Installing-the-App}&quot;">​</a></h2><p>Install KomaMRI with <code>pkg&gt; add KomaMRI</code>, then install the <code>koma</code> app (Julia 1.12+):</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Pkg</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Apps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;KomaMRI&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Installs koma app</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;" class="repl-prompt repl-prompt-julia">julia</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;" class="repl-prompt repl-prompt-julia">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Pkg.Apps.develop(path=&quot;/path/to/KomaMRI.jl&quot;) # Local checkout</span></span></code></pre></div><p>The executable is installed in <code>~/.julia/bin</code>. If <code>koma</code> is not found, add that directory to your <code>PATH</code>. The app command is named <code>koma</code>; Julia app names are executable names, not registered package names.</p><h2 id="Basic-Workflow" tabindex="-1">Basic Workflow <a class="header-anchor" href="#Basic-Workflow" aria-label="Permalink to &quot;Basic Workflow {#Basic-Workflow}&quot;">​</a></h2><p>With no arguments, <code>koma</code> opens the graphical interface with default inputs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span></span></code></pre></div><p>Add input files without output paths to preload the UI before it opens:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span></span></code></pre></div><p>Input files can be passed in any order. KomaMRI identifies them by extension: <code>.seq</code>, <code>.phantom</code> or <code>.h5</code>, and <code>.sys</code>.</p><h2 id="Loading-Simulation-Inputs" tabindex="-1">Loading Simulation Inputs <a class="header-anchor" href="#Loading-Simulation-Inputs" aria-label="Permalink to &quot;Loading Simulation Inputs {#Loading-Simulation-Inputs}&quot;">​</a></h2><p>Use <code>-i</code> or <code>--inputs</code> to pass a sequence, phantom, and scanner file. Missing inputs use the same defaults as the UI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span></span></code></pre></div><p>Scanner <code>.sys</code> files are accepted but ignored for now.</p><h2 id="Running-Simulation" tabindex="-1">Running Simulation <a class="header-anchor" href="#Running-Simulation" aria-label="Permalink to &quot;Running Simulation {#Running-Simulation}&quot;">​</a></h2><p>Add a simulation output path with <code>-o</code> or <code>--outputs</code> to run without opening the UI:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> raw.mrd</span></span></code></pre></div><p>Simulation output can be <code>.mrd</code> or <code>.mat</code>, selected from the output filename extension.</p><h2 id="Reconstructing-Image-using-MRIReco" tabindex="-1">Reconstructing Image using MRIReco <a class="header-anchor" href="#Reconstructing-Image-using-MRIReco" aria-label="Permalink to &quot;Reconstructing Image using MRIReco {#Reconstructing-Image-using-MRIReco}&quot;">​</a></h2><p>Pass a second output path to reconstruct after simulation. Reconstruction output is currently <code>.mat</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> raw.mrd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image.mat</span></span></code></pre></div><p>Use <code>_</code> to skip saving the simulation output:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> image.mat</span></span></code></pre></div><h2 id="Simulation-and-Reconstruction-Parameters" tabindex="-1">Simulation and Reconstruction Parameters <a class="header-anchor" href="#Simulation-and-Reconstruction-Parameters" aria-label="Permalink to &quot;Simulation and Reconstruction Parameters {#Simulation-and-Reconstruction-Parameters}&quot;">​</a></h2><p>Simulation and reconstruction parameters can be passed as repeated <code>KEY=VALUE</code> pairs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gpu=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reco=direct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> raw.mrd</span></span></code></pre></div><p>The long forms are <code>--sim-param</code> and <code>--recon-param</code>.</p><h2 id="Backend-and-Threading" tabindex="-1">Backend and Threading <a class="header-anchor" href="#Backend-and-Threading" aria-label="Permalink to &quot;Backend and Threading {#Backend-and-Threading}&quot;">​</a></h2><p>Simulations run on multi-threaded CPU by default. GPU backends can be loaded by name:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Metal</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> raw.mrd</span></span></code></pre></div><p>The selected backend package must be installed in your default Julia environment.</p><p>The app starts with CPU threading enabled automatically. To choose a thread count, pass Julia flags before <code>--</code> and KomaMRI arguments after it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">koma</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --threads=8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seq.seq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obj.phantom</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sys.sys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> raw.mrd</span></span></code></pre></div>`,35)])])}const g=a(n,[["render",p]]);export{c as __pageData,g as default};
